section.codeblock:
name: DITA variants
on: push: branches: [ "main" ]
jobs: build: runs-on: ubuntu-latest strategy: matrix: variant: - { name: web, ditaval: build/ditaval/web.ditaval, out: out/html5-web } - { name: admin, ditaval: build/ditaval/admin.ditaval, out: out/html5-admin } steps: - uses: actions/checkout@v4
- name: Build ${{ matrix.variant.name }} uses: dita-ot/dita-ot-action@master with: build: | dita -i dita/maps/book.ditamap -f html5 -o ${{ matrix.variant.out }} \ --propertyfile=build/html5.properties \ --args.filter=${{ matrix.variant.ditaval }}
- name: Upload artifacts uses: actions/upload-artifact@v4 with: name: ${{ matrix.variant.name }} path: ${{ matrix.variant.out }}
